async function main() {
  console.log('⚡ Adding article body sections to all 10 topics...\n');

  for (const [slug, sections] of Object.entries(ARTICLE_SECTIONS)) {
    const topic = await prisma.topic.findUnique({ where: { slug } });
    if (!topic) {
      console.log(`⚠️  Topic "${slug}" not found, skipping`);
      continue;
    }

    const existingContent = (topic.content && typeof topic.content === 'object') ? topic.content as Record<string, unknown> : {};
    const updatedContent = {
      ...existingContent,
      sections, // Strategy 1 in ReadModeArticle: content.sections with .body
    };

    await prisma.topic.update({
      where: { slug },
      data: { content: updatedContent },
    });

    console.log(`✅ ${slug} — ${sections.length} sections added`);
  }

  console.log('\n⚡ Done! All topics now have full article body content.');
}

main()
  .catch(console.error)
  .finally(() => prisma.$disconnect());
